/*
  Medication code master: populate formulary_drug_cd for existing CSV rows + ~200 new drugs.

  IMPORTANT:
  - Updates match by code_display (same text as medication_code_master.csv), NOT by id.
    If your DB never had id=1..40, id-only UPDATEs updated 0 rows — that is why "nothing happened".
  - Bulk insert is idempotent: skips rows whose formulary_drug_cd already exists.
  - Run on the correct database (USE EHRAssistData; or select DB in your tool).

  No GO — many JDBC clients send GO to the server and fail.
*/

-- If your SQL client does not select the DB automatically, uncomment:
-- USE EHRAssistData;

-- Before: confirm database and row count (should show your real totals)
SELECT DB_NAME() AS current_database;
SELECT COUNT(*) AS medication_code_master_rows FROM medication_code_master;

-- ---------- Updates: original 40 drugs — match CSV code_display exactly (FD + RxNorm from CSV) ----------
UPDATE m
SET m.formulary_drug_cd = v.formulary_drug_cd
FROM medication_code_master AS m
INNER JOIN (
    VALUES
        (N'Metformin 500 MG Oral Tablet',                    N'FD860975'),
