WHERE NOT EXISTS (
    SELECT 1 FROM medication_code_master AS m WHERE m.formulary_drug_cd = src.formulary_drug_cd
);

-- After: you should see total_rows and how many have formulary_drug_cd set
SELECT
    COUNT(*) AS total_rows,
    SUM(CASE WHEN formulary_drug_cd IS NOT NULL THEN 1 ELSE 0 END) AS rows_with_formulary_cd
FROM medication_code_master;

-- Rows that still have NULL formulary (should be 0 for CSV rows if code_display matched)
SELECT id, code_display, generic_name, formulary_drug_cd
FROM medication_code_master
WHERE formulary_drug_cd IS NULL;

-- Optional: ensure unique formulary codes (run once if not already created)
IF NOT EXISTS (SELECT 1 FROM sys.indexes WHERE name = N'UX_medication_code_master_formulary_drug_cd' AND object_id = OBJECT_ID(N'medication_code_master'))
BEGIN
    CREATE UNIQUE NONCLUSTERED INDEX UX_medication_code_master_formulary_drug_cd
        ON medication_code_master (formulary_drug_cd)
        WHERE formulary_drug_cd IS NOT NULL;
END
